function calculate(op: string, a: number, b: number): number | string {
  const ops: Record<string, number> = { "+": a + b, "-": a - b, "*": a * b, "/": a / b };
  return ops[op] ?? "Unknown operator";
}

const [, , aArg, op, bArg] = process.argv;
console.log(calculate(op, Number(aArg), Number(bArg)));
